+            "VERIFIER_SHORTCUT_GUARD::CONNECTOR_REPLAY_HELPER_MARKER",
+            "src/connector/verifier_sdk.rs",
+            CONNECTOR_VERIFIER_SOURCE,
+            "STRUCTURAL_ONLY_REPLAY_HELPER_POSTURE",
+        );
+
+        assert_guard_absent(
+            "VERIFIER_SHORTCUT_GUARD::NO_SDK_CAPSULE_IMPORT_IN_VEP",
